                    {"type": "quiz", "question": "Какая горячая клавиша переключает вид «до/после» в Lightroom?", "options": [{"id": "a", "text": "R", "correct": False}, {"id": "b", "text": "D", "correct": False}, {"id": "c", "text": "\\", "correct": True}, {"id": "d", "text": "K", "correct": False}]},
